public with sharing class EmployeeProjectService {

    /**
     * Inner class to hold Employee Project input parameters.
     */
    public class EmployeeProjectInput {
        public String projectName;
        public String employeeName;
        public String status;
        public Date startDate;
        public Date endDate;
        public Decimal budget;

        public EmployeeProjectInput(
            String projectName,
            String employeeName,
            String status,
            Date startDate,
            Date endDate,
            Decimal budget
        ) {
            this.projectName  = projectName;
            this.employeeName = employeeName;
            this.status       = status;
            this.startDate    = startDate;
            this.endDate      = endDate;
            this.budget       = budget;
        }
    }

    /**
     * Creates and inserts a list of Employee_Project__c records.
     * @param inputs  List of EmployeeProjectInput wrapper objects
     * @return        List of inserted Employee_Project__c records
     */
    public static List<Employee_Project__c> createEmployeeProjects(
        List<EmployeeProjectInput> inputs
    ) {
        if (inputs == null || inputs.isEmpty()) {
            return new List<Employee_Project__c>();
        }

        List<Employee_Project__c> recordsToInsert = new List<Employee_Project__c>();

        for (EmployeeProjectInput input : inputs) {
            Employee_Project__c ep = new Employee_Project__c(
                Project_Name__c  = input.projectName,
                Employee_Name__c = input.employeeName,
                Status__c        = input.status,
                Start_Date__c    = input.startDate,
                End_Date__c      = input.endDate,
                Budget__c        = input.budget
            );
            recordsToInsert.add(ep);
        }

        insert recordsToInsert;
        return recordsToInsert;
    }

    /**
     * Convenience method to create a single Employee Project record.
     * @param projectName   Name of the project
     * @param employeeName  Name of the employee
     * @param status        Status picklist value
     * @param startDate     Project start date
     * @param endDate       Project end date
     * @param budget        Allocated budget
     * @return              Inserted Employee_Project__c record
     */
    public static Employee_Project__c createSingleEmployeeProject(
        String projectName,
        String employeeName,
        String status,
        Date startDate,
        Date endDate,
        Decimal budget
    ) {
        List<EmployeeProjectInput> inputs = new List<EmployeeProjectInput>{
            new EmployeeProjectInput(projectName, employeeName, status, startDate, endDate, budget)
        };
        List<Employee_Project__c> results = createEmployeeProjects(inputs);
        return results.isEmpty() ? null : results[0];
    }
}

@isTest
private class EmployeeProjectServiceTest {

