    // Helper: builds a single EmployeeProjectInput
    // ----------------------------------------------------------------
    private static EmployeeProjectService.EmployeeProjectInput buildInput(
        String projectName,
        String employeeName,
        String status,
        Date startDate,
        Date endDate,
        Decimal budget
    ) {
        return new EmployeeProjectService.EmployeeProjectInput(
            projectName, employeeName, status, startDate, endDate, budget
        );
    }

    // ----------------------------------------------------------------
    // Test 1: Single record insert via convenience method
    // ----------------------------------------------------------------
    @isTest
    static void testCreateSingleEmployeeProject() {
        Date startDate = Date.newInstance(2024, 1, 15);
        Date endDate   = Date.newInstance(2024, 6, 30);

        Test.startTest();
        Employee_Project__c result = EmployeeProjectService.createSingleEmployeeProject(
            'Apollo Initiative',
            'Jane Doe',
            'In Progress',
            startDate,
            endDate,
            50000.00
        );
        Test.stopTest();

        System.assertNotEquals(null, result.Id,
            'Record should have been inserted and have an Id.');

        Employee_Project__c queried = [
            SELECT Project_Name__c, Employee_Name__c, Status__c,
                   Start_Date__c, End_Date__c, Budget__c
            FROM Employee_Project__c
            WHERE Id = :result.Id
            LIMIT 1
        ];

        System.assertEquals('Apollo Initiative', queried.Project_Name__c,
            'Project Name should match.');
        System.assertEquals('Jane Doe', queried.Employee_Name__c,
            'Employee Name should match.');
        System.assertEquals('In Progress', queried.Status__c,
            'Status should match.');
        System.assertEquals(startDate, queried.Start_Date__c,
            'Start Date should match.');
        System.assertEquals(endDate, queried.End_Date__c,
            'End Date should match.');
        System.assertEquals(50000.00, queried.Budget__c,
            'Budget should match.');
    }

    // ----------------------------------------------------------------
    // Test 2: Bulk insert of 200 records
    // ----------------------------------------------------------------
