    static void testBulkCreateEmployeeProjects() {
        List<EmployeeProjectService.EmployeeProjectInput> inputs =
            new List<EmployeeProjectService.EmployeeProjectInput>();

        for (Integer i = 1; i <= 200; i++) {
            inputs.add(buildInput(
                'Project ' + i,
                'Employee ' + i,
                'Not Started',
                Date.newInstance(2024, 1, 1),
                Date.newInstance(2024, 12, 31),
                1000.00 * i
            ));
        }

        Test.startTest();
        List<Employee_Project__c> results =
            EmployeeProjectService.createEmployeeProjects(inputs);
        Test.stopTest();

        System.assertEquals(200, results.size(),
            'Should have inserted 200 records.');

        Integer dbCount = [
            SELECT COUNT()
            FROM Employee_Project__c
        ];
        System.assertEquals(200, dbCount,
            'Database should contain exactly 200 records.');
    }

    // ----------------------------------------------------------------
    // Test 3: Empty input list returns empty list (no DML)
    // ----------------------------------------------------------------
    @isTest
    static void testEmptyInputReturnsEmptyList() {
        Test.startTest();
        List<Employee_Project__c> results =
            EmployeeProjectService.createEmployeeProjects(
                new List<EmployeeProjectService.EmployeeProjectInput>()
            );
        Test.stopTest();

        System.assertEquals(0, results.size(),
            'Empty input should return an empty list.');
    }

    // ----------------------------------------------------------------
    // Test 4: Null input list returns empty list (no DML)
    // ----------------------------------------------------------------
    @isTest
    static void testNullInputReturnsEmptyList() {
        Test.startTest();
        List<Employee_Project__c> results =
            EmployeeProjectService.createEmployeeProjects(null);
        Test.stopTest();

        System.assertEquals(0, results.size(),
            'Null input should return an empty list.');
    }

    // ----------------------------------------------------------------
    // Test 5: Verify default Status picklist value
    // ----------------------------------------------------------------
    @isTest
    static void testDefaultStatusOnInsert() {
        Test.startTest();
        Employee_Project__c result = EmployeeProjectService.createSingleEmployeeProject(
            'Beta Project',
            'John Smith',
            'Not Started',
            Date.today(),
            Date.today().addMonths(3),
            75000.00
        );
        Test.stopTest();

        Employee_Project__c queried = [
            SELECT Status__c
            FROM Employee_Project__c
            WHERE Id = :result.Id
            LIMIT 1
        ];

        System.assertEquals('Not Started', queried.Status__c,
            'Default status should be Not Started.');
    }
}

