public with sharing class EmployeeProjectService {

    /**
     * Wrapper class to hold Employee Project data before insert
     */
    public class EmployeeProjectWrapper {
        public String projectName;
        public String employeeName;
        public String status;
        public Date startDate;
        public Date endDate;
        public Decimal budget;

        public EmployeeProjectWrapper(
            String projectName,
            String employeeName,
            String status,
            Date startDate,
            Date endDate,
            Decimal budget
        ) {
            this.projectName  = projectName;
            this.employeeName = employeeName;
            this.status       = status;
            this.startDate    = startDate;
            this.endDate      = endDate;
            this.budget       = budget;
        }
    }

    /**
     * Bulkified method to insert a list of Employee Project records.
     * @param wrappers - List of EmployeeProjectWrapper instances
     * @return List of inserted Employee_Project__c records
     * @throws IllegalArgumentException if the input list is null or empty
     */
    public static List<Employee_Project__c> createEmployeeProjects(
        List<EmployeeProjectWrapper> wrappers
    ) {
        if (wrappers == null || wrappers.isEmpty()) {
            throw new IllegalArgumentException(
                'Input list cannot be null or empty.'
            );
        }

        List<Employee_Project__c> projectsToInsert = new List<Employee_Project__c>();

        for (EmployeeProjectWrapper w : wrappers) {
            Employee_Project__c ep = new Employee_Project__c(
                Project_Name__c  = w.projectName,
                Employee_Name__c = w.employeeName,
                Status__c        = w.status,
                Start_Date__c    = w.startDate,
                End_Date__c      = w.endDate,
                Budget__c        = w.budget
            );
            projectsToInsert.add(ep);
        }

        try {
            insert projectsToInsert;
        } catch (DmlException e) {
            System.debug('DML Error during Employee Project insert: ' + e.getMessage());
            throw e;
        }

        return projectsToInsert;
    }

    /**
     * Query Employee Projects by Status.
     * @param status - The picklist value to filter by
     * @return List of matching Employee_Project__c records
     */
    public static List<Employee_Project__c> getProjectsByStatus(String status) {
        if (String.isBlank(status)) {
            throw new IllegalArgumentException('Status filter cannot be blank.');
        }

        return [
            SELECT Id,
                   Name,
                   Project_Name__c,
                   Employee_Name__c,
                   Status__c,
                   Start_Date__c,
                   End_Date__c,
                   Budget__c
            FROM   Employee_Project__c
            WHERE  Status__c = :status
            ORDER BY Start_Date__c ASC
        ];
    }

    /**
     * Sample insert logic — demonstrates creating 3 Employee Project records.
     */
    public static void sampleInsert() {
        List<EmployeeProjectWrapper> samples = new List<EmployeeProjectWrapper> {
            new EmployeeProjectWrapper(
                'Apollo Initiative',
                'Jane Doe',
                'Active',
                Date.newInstance(2024, 1, 15),
                Date.newInstance(2024, 6, 30),
                75000.00
            ),
            new EmployeeProjectWrapper(
                'Orion Rollout',
                'John Smith',
                'On Hold',
                Date.newInstance(2024, 3, 1),
                Date.newInstance(2024, 9, 1),
                120000.00
            ),
            new EmployeeProjectWrapper(
                'Zenith Upgrade',
                'Alice Johnson',
                'Completed',
                Date.newInstance(2023, 7, 1),
                Date.newInstance(2023, 12, 31),
                45000.00
            )
        };

        List<Employee_Project__c> inserted = createEmployeeProjects(samples);
        System.debug('Successfully inserted ' + inserted.size() + ' Employee Project records.');
    }
}

